import { useState } from "react";
import { PlatformIcon } from "./platform-icon";
import { Button } from "./ui/button";
import { Check, Copy, Edit2, Sparkles, RefreshCw, AlertCircle } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useToast } from "@/hooks/use-toast";

interface CaptionCardProps {
  platform: string;
  caption: string;
  onUpdate: (newCaption: string) => void;
  onRefine: (instruction: string) => Promise<void>;
  onRewrite: () => Promise<void>;
  isProcessing: boolean;
}

export function CaptionCard({ platform, caption, onUpdate, onRefine, onRewrite, isProcessing }: CaptionCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [localText, setLocalText] = useState(caption);
  const [refineInstruction, setRefineInstruction] = useState("");
  const [isRefiningPanelOpen, setIsRefiningPanelOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const { toast } = useToast();

  const handleCopy = async () => {
    await navigator.clipboard.writeText(localText);
    setCopied(true);
    toast({ title: "Copied to clipboard", description: `${platform} caption copied.` });
    setTimeout(() => setCopied(false), 2000);
  };

