import { useState, useCallback, useEffect } from "react";
import { Layout } from "@/components/layout";
import { useDropzone } from "react-dropzone";
import { UploadCloud, FileImage, Settings2, Sparkles, Download, Save, Loader2 } from "lucide-react";
import { compressImage, createThumbnail, formatBytes, cn } from "@/lib/utils";
import { useGetSettings, useGenerateCaptions, useRefineCaption, useRewriteCaption, useSaveHistory } from "@workspace/api-client-react";
import { CaptionCard } from "@/components/caption-card";
import { PlatformIcon, platformLabel } from "@/components/platform-icon";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { motion, AnimatePresence } from "framer-motion";
import type { CaptionVariantResult } from "@workspace/api-client-react";

const PLATFORM_ORDER = ["instagram", "facebook", "substack_post", "substack_note", "x", "bluesky"];

type VariantOverride = { variantName: string; instructions: string };
type PlatformOverride = { audience: string; variants: VariantOverride[] };

export default function Generator() {
  const { data: globalSettings } = useGetSettings();
  const generateMutation = useGenerateCaptions();
  const refineMutation = useRefineCaption();
  const rewriteMutation = useRewriteCaption();
  const saveHistoryMutation = useSaveHistory();
  const { toast } = useToast();

  // Upload State
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [base64Data, setBase64Data] = useState<string | null>(null);
  const [compressedBytes, setCompressedBytes] = useState<number | null>(null);
  const [imageMediaType, setImageMediaType] = useState<string>("image/jpeg");

  // Input State
  const [mapType, setMapType] = useState<"geopolitical" | "historical" | "data-infographic" | "other">("geopolitical");
  const [contextNotes, setContextNotes] = useState("");

  // Overrides State — per-platform, with audience + variant array
  const [overrides, setOverrides] = useState<Record<string, PlatformOverride>>({});
  const [showOverrides, setShowOverrides] = useState(false);

  // Results State — per-platform array of {variantName, caption}
  const [results, setResults] = useState<Record<string, CaptionVariantResult[]> | null>(null);
  const [processingVariants, setProcessingVariants] = useState<Record<string, boolean>>({});

  useEffect(() => {
    if (globalSettings && Object.keys(overrides).length === 0) {
      resetOverrides();
    }
  }, [globalSettings]);

  const resetOverrides = () => {
    if (!globalSettings) return;
    const grouped: Record<string, PlatformOverride> = {};
    for (const s of globalSettings) {
      if (!grouped[s.platformId]) {
        grouped[s.platformId] = { audience: s.audience, variants: [] };
      }
      grouped[s.platformId].variants.push({ variantName: s.variantName, instructions: s.instructions });
    }
    setOverrides(grouped);
  };

  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    const selected = acceptedFiles[0];
    if (selected) {
      setFile(selected);
      setPreview(URL.createObjectURL(selected));
      setBase64Data(null);
      setCompressedBytes(null);
      try {
        const result = await compressImage(selected);
        setBase64Data(result.base64);
        setImageMediaType(result.mediaType);
        setCompressedBytes(result.compressedBytes);
      } catch {
        toast({ variant: "destructive", title: "Error", description: "Failed to process image." });
      }
    }
  }, [toast]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 'image/jpeg': [], 'image/png': [], 'image/webp': [] },
    maxFiles: 1,
  });

  const handleGenerate = async () => {
    if (!base64Data || !file) return;
    setResults(null);
    try {
      const data = await generateMutation.mutateAsync({
        data: {
          imageData: base64Data,
          imageMediaType,
          mapType,
          contextNotes: contextNotes || null,
          platformOverrides: overrides as any,
        },
      });
      setResults(data as any);
      toast({ title: "Analysis Complete", description: "Captions generated successfully." });
    } catch {
      toast({ variant: "destructive", title: "Generation Failed", description: "Could not generate captions. Please try again." });
    }
  };

  const handleCaptionUpdate = (platform: string, variantIdx: number, text: string) => {
    if (!results) return;
    const updated = [...(results[platform] ?? [])];
    updated[variantIdx] = { ...updated[variantIdx], caption: text };
    setResults({ ...results, [platform]: updated });
  };

  const variantKey = (platform: string, variantIdx: number) => `${platform}_${variantIdx}`;

  const handleRefine = async (platform: string, variantIdx: number, instruction: string) => {
    if (!results) return;
    const key = variantKey(platform, variantIdx);
    setProcessingVariants(p => ({ ...p, [key]: true }));
    try {
      const res = await refineMutation.mutateAsync({
        data: { platform, currentCaption: results[platform][variantIdx].caption, instruction },
      });
      handleCaptionUpdate(platform, variantIdx, res.caption);
    } catch {
      toast({ variant: "destructive", title: "Refinement Failed", description: "Error refining caption." });
    } finally {
      setProcessingVariants(p => ({ ...p, [key]: false }));
    }
  };

  const handleRewrite = async (platform: string, variantIdx: number) => {
    if (!base64Data || !file || !results) return;
    const key = variantKey(platform, variantIdx);
    const variant = overrides[platform]?.variants[variantIdx];
    setProcessingVariants(p => ({ ...p, [key]: true }));
    try {
      const res = await rewriteMutation.mutateAsync({
        data: {
          imageData: base64Data,
          imageMediaType,
          platform,
          mapType,
          contextNotes: contextNotes || null,
          instructions: variant?.instructions ?? "",
          audience: overrides[platform]?.audience ?? "",
        },
      });
      handleCaptionUpdate(platform, variantIdx, res.caption);
    } catch {
      toast({ variant: "destructive", title: "Rewrite Failed", description: "Error rewriting caption." });
    } finally {
      setProcessingVariants(p => ({ ...p, [key]: false }));
    }
  };

  const handleDownloadAll = () => {
    if (!results) return;
    const lines: string[] = [];
    for (const pid of PLATFORM_ORDER) {
      const variants = results[pid];
      if (!variants) continue;
      lines.push(`${platformLabel(pid).toUpperCase()} ${"─".repeat(40)}`);
      for (const v of variants) {
        lines.push(`[${v.variantName}]\n${v.caption}\n`);
      }
      lines.push("");
    }
    const blob = new Blob([lines.join("\n")], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `diplocaption-${Date.now()}.txt`;
    a.click();
  };

  const handleSaveHistory = async () => {
    if (!results || !base64Data || !file) return;
    try {
      const thumb = await createThumbnail(base64Data, imageMediaType, 400);
      await saveHistoryMutation.mutateAsync({
        data: { mapType, contextNotes: contextNotes || null, imageThumbnail: thumb, captions: results },
      });
      toast({ title: "Saved to History", description: "Session securely logged." });
    } catch {
      toast({ variant: "destructive", title: "Save Failed", description: "Could not save history." });
    }
  };

  return (
    <Layout>
      <div className="max-w-4xl mx-auto space-y-8">

        {/* Main Upload & Config Area */}
        <div className="glass-panel rounded-3xl p-6 md:p-10">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">

            {/* Left Col: Upload */}
            <div className="space-y-4">
              <h2 className="font-serif text-xl font-bold">Source Material</h2>
              <div
                {...getRootProps()}
                className={cn(
                  "relative h-64 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center p-6 text-center cursor-pointer transition-all overflow-hidden",
                  isDragActive ? "border-primary bg-primary/5" : "border-white/20 hover:border-white/40 hover:bg-white/[0.02]",
                  preview ? "border-none" : "",
                )}
              >
                <input {...getInputProps()} />
                {preview ? (
                  <>
                    <img src={preview} alt="Upload preview" className="absolute inset-0 w-full h-full object-cover opacity-60" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent" />
                    <div className="relative z-10 mt-auto w-full flex items-center justify-between">
                      <div className="flex items-center gap-2 text-white bg-black/50 backdrop-blur-md px-3 py-1.5 rounded-lg border border-white/10">
                        <FileImage className="w-4 h-4" />
                        <span className="text-xs font-mono truncate max-w-[120px]">{file?.name}</span>
                        {compressedBytes != null
                          ? <span className="text-xs font-mono text-primary/80 shrink-0">{formatBytes(compressedBytes)}</span>
                          : <Loader2 className="w-3 h-3 animate-spin shrink-0 text-muted-foreground" />
                        }
                      </div>
                      <Button size="sm" variant="secondary" onClick={(e) => { e.stopPropagation(); setFile(null); setPreview(null); setBase64Data(null); setCompressedBytes(null); }} className="h-8 px-3 rounded-lg z-20 relative">
                        Change
                      </Button>
                    </div>
                  </>
                ) : (
                  <>
                    <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mb-4">
                      <UploadCloud className="w-8 h-8 text-primary" />
                    </div>
                    <p className="font-medium text-foreground mb-1">Drag map image here</p>
                    <p className="text-xs text-primary/80 font-sans underline underline-offset-2 cursor-pointer">or click to browse files</p>
                    <p className="text-xs text-muted-foreground font-sans mt-1">JPG, PNG, WEBP up to 10MB</p>
                  </>
                )}
              </div>
            </div>

            {/* Right Col: Context */}
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="block text-xs font-semibold text-muted-foreground uppercase tracking-widest">
                  Map Type Classification
                </label>
                <select
                  value={mapType}
                  onChange={(e) => setMapType(e.target.value as any)}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-sm text-foreground focus:outline-none focus:border-primary/50 appearance-none font-sans"
                >
                  <option value="geopolitical">Geopolitical / Boundaries</option>
                  <option value="historical">Historical Context</option>
                  <option value="data-infographic">Data / Infographic</option>
                  <option value="other">Other</option>
                </select>
              </div>

              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <label className="block text-xs font-semibold text-muted-foreground uppercase tracking-widest">
                    Briefing Notes (Optional)
                  </label>
                  <span className="text-xs text-muted-foreground font-mono">{contextNotes.length}/500</span>
                </div>
                <textarea
                  value={contextNotes}
                  onChange={(e) => setContextNotes(e.target.value)}
                  maxLength={500}
                  placeholder="Key takeaways, specific framing, or required talking points..."
                  className="w-full h-32 bg-black/40 border border-white/10 rounded-xl p-4 text-sm text-foreground focus:outline-none focus:border-primary/50 resize-none font-sans placeholder:text-white/20"
                />
              </div>
            </div>
          </div>

          {/* Session Overrides */}
          <div className="mt-8 pt-6 border-t border-white/10">
            <button
              onClick={() => setShowOverrides(!showOverrides)}
              className="flex items-center gap-2 text-sm font-semibold text-primary hover:text-primary/80 transition-colors uppercase tracking-widest"
            >
              <Settings2 className="w-4 h-4" />
              Session Overrides
            </button>

            <AnimatePresence>
              {showOverrides && (
                <motion.div
                  initial={{ height: 0, opacity: 0 }}
                  animate={{ height: "auto", opacity: 1 }}
                  exit={{ height: 0, opacity: 0 }}
                  className="overflow-hidden mt-6"
                >
                  <div className="bg-black/20 rounded-2xl p-6 border border-white/5 space-y-6">
                    <p className="text-sm text-muted-foreground">Adjust instructions for this specific generation. Will not overwrite global settings.</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      {PLATFORM_ORDER.map((pid) => {
                        const po = overrides[pid];
                        if (!po) return null;
                        return (
                          <div key={pid} className="space-y-3 bg-white/[0.02] p-4 rounded-xl border border-white/5">
                            <div className="flex items-center gap-2 mb-1">
                              <PlatformIcon platform={pid} />
                              <span className="font-semibold text-sm">{platformLabel(pid)}</span>
                            </div>
                            <input
                              value={po.audience}
                              onChange={(e) => setOverrides(prev => ({ ...prev, [pid]: { ...prev[pid], audience: e.target.value } }))}
                              placeholder="Audience"
                              className="w-full bg-black/40 border border-white/5 rounded-lg px-3 py-2 text-xs focus:border-primary/50"
                            />
                            {po.variants.map((v, i) => (
                              <div key={i} className="space-y-1">
                                <span className="text-xs text-muted-foreground font-mono">{v.variantName}</span>
                                <textarea
                                  value={v.instructions}
                                  onChange={(e) => {
                                    const variants = [...po.variants];
                                    variants[i] = { ...variants[i], instructions: e.target.value };
                                    setOverrides(prev => ({ ...prev, [pid]: { ...prev[pid], variants } }));
                                  }}
                                  placeholder="Instructions"
                                  className="w-full h-16 bg-black/40 border border-white/5 rounded-lg px-3 py-2 text-xs focus:border-primary/50 resize-none"
                                />
                              </div>
                            ))}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Generate Action */}
          <div className="mt-8 pt-8 border-t border-white/10 flex justify-end">
            <Button
              size="lg"
              className="w-full md:w-auto min-w-[200px] h-14 text-base tracking-wide font-bold"
              disabled={!file || !base64Data || generateMutation.isPending}
              onClick={handleGenerate}
            >
              {generateMutation.isPending ? (
                <><Loader2 className="w-5 h-5 mr-2 animate-spin" />ANALYZING...</>
              ) : (
                <><Sparkles className="w-5 h-5 mr-2" />GENERATE CAPTIONS</>
              )}
            </Button>
          </div>
        </div>

        {/* Results Section */}
        {results && (
          <motion.div
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            className="pt-8 space-y-8"
          >
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 border-b border-white/10 pb-6">
              <h2 className="font-serif text-3xl font-bold text-primary">Intelligence Output</h2>
              <div className="flex gap-3 w-full sm:w-auto">
                <Button variant="outline" className="flex-1 sm:flex-none gap-2 border-white/10 hover:bg-white/5" onClick={handleDownloadAll}>
                  <Download className="w-4 h-4" /> Download All
                </Button>
                <Button className="flex-1 sm:flex-none gap-2" onClick={handleSaveHistory} disabled={saveHistoryMutation.isPending}>
                  {saveHistoryMutation.isPending ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                  Save Log
                </Button>
              </div>
            </div>

            {PLATFORM_ORDER.map((pid) => {
              const variants = results[pid];
              if (!variants?.length) return null;
              return (
                <div key={pid} className="space-y-4">
                  <div className="flex items-center gap-3">
                    <PlatformIcon platform={pid} className="text-xl" />
                    <h3 className="font-serif text-xl font-bold text-foreground">{platformLabel(pid)}</h3>
                  </div>
                  <div className="space-y-4 pl-0 md:pl-8">
                    {variants.map((v, i) => (
                      <CaptionCard
                        key={i}
                        platform={pid}
                        variantName={variants.length > 1 ? v.variantName : undefined}
                        caption={v.caption}
                        onUpdate={(text) => handleCaptionUpdate(pid, i, text)}
                        onRefine={(instruction) => handleRefine(pid, i, instruction)}
                        onRewrite={() => handleRewrite(pid, i)}
                        isProcessing={!!processingVariants[variantKey(pid, i)]}
                      />
                    ))}
                  </div>
                </div>
              );
            })}
          </motion.div>
        )}

      </div>
    </Layout>
  );
}

