      setResults(data as any);
      toast({ title: "Analysis Complete", description: "Captions generated successfully." });
    } catch {
      toast({ variant: "destructive", title: "Generation Failed", description: "Could not generate captions. Please try again." });
    }
  };

  const handleCaptionUpdate = (platform: string, variantIdx: number, text: string) => {
    if (!results) return;
    const updated = [...(results[platform] ?? [])];
    updated[variantIdx] = { ...updated[variantIdx], caption: text };
    setResults({ ...results, [platform]: updated });
  };

  const variantKey = (platform: string, variantIdx: number) => `${platform}_${variantIdx}`;

  const handleRefine = async (platform: string, variantIdx: number, instruction: string) => {
    if (!results) return;
    const key = variantKey(platform, variantIdx);
    setProcessingVariants(p => ({ ...p, [key]: true }));
    try {
      const res = await refineMutation.mutateAsync({
        data: { platform, currentCaption: results[platform][variantIdx].caption, instruction },
      });
      handleCaptionUpdate(platform, variantIdx, res.caption);
    } catch {
      toast({ variant: "destructive", title: "Refinement Failed", description: "Error refining caption." });
    } finally {
      setProcessingVariants(p => ({ ...p, [key]: false }));
    }
  };

  const handleRewrite = async (platform: string, variantIdx: number) => {
    if (!base64Data || !file || !results) return;
    const key = variantKey(platform, variantIdx);
    const variant = overrides[platform]?.variants[variantIdx];
    setProcessingVariants(p => ({ ...p, [key]: true }));
    try {
      const res = await rewriteMutation.mutateAsync({
        data: {
          imageData: base64Data,
          imageMediaType,
          platform,
          mapType,
          contextNotes: contextNotes || null,
          instructions: variant?.instructions ?? "",
          audience: overrides[platform]?.audience ?? "",
        },
      });
      handleCaptionUpdate(platform, variantIdx, res.caption);
    } catch {
      toast({ variant: "destructive", title: "Rewrite Failed", description: "Error rewriting caption." });
    } finally {
      setProcessingVariants(p => ({ ...p, [key]: false }));
    }
  };

  const handleDownloadAll = () => {
    if (!results) return;
    const lines: string[] = [];
    for (const pid of PLATFORM_ORDER) {
      const variants = results[pid];
      if (!variants) continue;
      lines.push(`${platformLabel(pid).toUpperCase()} ${"─".repeat(40)}`);
      for (const v of variants) {
        lines.push(`[${v.variantName}]\n${v.caption}\n`);
      }
      lines.push("");
    }
    const blob = new Blob([lines.join("\n")], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `diplocaption-${Date.now()}.txt`;
    a.click();
  };

  const handleSaveHistory = async () => {
    if (!results || !base64Data || !file) return;
    try {
      const thumb = await createThumbnail(base64Data, imageMediaType, 400);
      await saveHistoryMutation.mutateAsync({
        data: { mapType, contextNotes: contextNotes || null, imageThumbnail: thumb, captions: results },
      });
      toast({ title: "Saved to History", description: "Session securely logged." });
    } catch {
      toast({ variant: "destructive", title: "Save Failed", description: "Could not save history." });
    }
  };

  return (
    <Layout>
      <div className="max-w-4xl mx-auto space-y-8">

        {/* Main Upload & Config Area */}
        <div className="glass-panel rounded-3xl p-6 md:p-10">
