}

import { useState } from "react";
import { PlatformIcon, platformLabel } from "./platform-icon";
import { Button } from "./ui/button";
import { Check, Copy, Edit2, Sparkles, RefreshCw, AlertCircle } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useToast } from "@/hooks/use-toast";

interface CaptionCardProps {
  platform: string;
  variantName?: string;
  caption: string;
  onUpdate: (newCaption: string) => void;
  onRefine: (instruction: string) => Promise<void>;
  onRewrite: () => Promise<void>;
  isProcessing: boolean;
}

export function CaptionCard({ platform, variantName, caption, onUpdate, onRefine, onRewrite, isProcessing }: CaptionCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [localText, setLocalText] = useState(caption);
  const [refineInstruction, setRefineInstruction] = useState("");
  const [isRefiningPanelOpen, setIsRefiningPanelOpen] = useState(false);
  const [copied, setCopied] = useState(false);
  const { toast } = useToast();

  const handleCopy = async () => {
    await navigator.clipboard.writeText(localText);
    setCopied(true);
    toast({ title: "Copied to clipboard", description: `${platform} caption copied.` });
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSaveEdit = () => {
    onUpdate(localText);
    setIsEditing(false);
  };

  const handleCancelEdit = () => {
    setLocalText(caption);
    setIsEditing(false);
  };

  const handleRefineSubmit = async () => {
    if (!refineInstruction.trim()) return;
    await onRefine(refineInstruction);
    setRefineInstruction("");
    setIsRefiningPanelOpen(false);
  };

  // Sync local text when external caption changes (like after AI refine)
  if (caption !== localText && !isEditing) {
    setLocalText(caption);
  }

  const getCharLimit = () => {
    if (platform === 'x') return 280;
    if (platform === 'bluesky') return 300;
    return null;
  };

  const limit = getCharLimit();
  const isOverLimit = limit ? localText.length > limit : false;

  return (
    <div className="glass-panel rounded-2xl overflow-hidden flex flex-col">
      <div className="px-6 py-4 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
        <div className="flex items-center gap-3">
          <PlatformIcon platform={platform} className="text-xl" />
          <h3 className="font-serif font-semibold text-lg">{platformLabel(platform)}</h3>
        </div>
        <div className="flex items-center gap-2">
          {limit && (
            <span className={`text-xs font-mono px-2 py-1 rounded-md ${isOverLimit ? 'bg-destructive/20 text-destructive' : 'bg-white/5 text-muted-foreground'}`}>
              {localText.length} / {limit}
            </span>
          )}
          <Button variant="ghost" size="icon" onClick={handleCopy} title="Copy">
            {copied ? <Check className="w-4 h-4 text-green-400" /> : <Copy className="w-4 h-4 text-muted-foreground" />}
          </Button>
        </div>
      </div>

      <div className="p-6 flex-1 relative group">
        {isProcessing && (
          <div className="absolute inset-0 bg-background/50 backdrop-blur-sm z-10 flex items-center justify-center">
            <RefreshCw className="w-6 h-6 text-primary animate-spin" />
          </div>
        )}

        {isEditing ? (
          <div className="space-y-3">
            <textarea
              className="w-full h-48 bg-black/20 border border-white/10 rounded-xl p-4 text-foreground focus:outline-none focus:border-primary/50 focus:ring-1 focus:ring-primary/50 resize-none font-sans"
              value={localText}
              onChange={(e) => setLocalText(e.target.value)}
            />
            <div className="flex justify-end gap-2">
              <Button variant="ghost" size="sm" onClick={handleCancelEdit}>Cancel</Button>
              <Button size="sm" onClick={handleSaveEdit}>Save Edits</Button>
            </div>
          </div>
        ) : (
          <div 
            className="group relative cursor-text min-h-[120px]"
            onClick={() => setIsEditing(true)}
          >
            <p className="whitespace-pre-wrap text-muted-foreground group-hover:text-foreground transition-colors font-sans leading-relaxed">
              {localText || "No caption generated."}
            </p>
            <div className="absolute top-0 right-0 opacity-0 group-hover:opacity-100 transition-opacity bg-background/80 p-1 rounded-md border border-white/10">
              <Edit2 className="w-4 h-4 text-muted-foreground" />
            </div>
          </div>
        )}
      </div>

      <div className="px-6 py-4 border-t border-white/5 bg-black/20 flex flex-wrap items-center justify-between gap-4">
        <div className="flex gap-2">
          <Button 
            variant="outline" 
            size="sm" 
            className="gap-2 border-white/10 hover:border-primary/50 hover:text-primary"
            onClick={() => setIsRefiningPanelOpen(!isRefiningPanelOpen)}
          >
            <Sparkles className="w-4 h-4" />
            Refine with AI
          </Button>
          <Button 
            variant="ghost" 
            size="sm" 
            className="gap-2 text-muted-foreground hover:text-foreground"
            onClick={onRewrite}
            disabled={isProcessing}
          >
            <RefreshCw className="w-4 h-4" />
            Rewrite Complete
          </Button>
        </div>
      </div>

      <AnimatePresence>
        {isRefiningPanelOpen && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="overflow-hidden bg-primary/5 border-t border-primary/20"
          >
            <div className="p-4 flex gap-3">
              <input
                type="text"
                placeholder="E.g., Make it punchier, add more emojis..."
                className="flex-1 bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-sm focus:outline-none focus:border-primary"
                value={refineInstruction}
                onChange={(e) => setRefineInstruction(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleRefineSubmit()}
              />
              <Button size="sm" onClick={handleRefineSubmit} disabled={isProcessing || !refineInstruction.trim()}>
                Refine
              </Button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

