import { Router, type IRouter } from "express";
import { and, eq } from "drizzle-orm";
import { db, pool, platformSettingsTable } from "@workspace/db";
import {
  GetSettingsResponse,
  UpdateVariantBody,
  UpdateVariantParams,
  UpdateVariantResponse,
  CreateVariantBody,
  CreateVariantParams,
  DeleteVariantParams,
  UpdatePlatformAudienceBody,
  UpdatePlatformAudienceParams,
} from "@workspace/api-zod";
import { requireAuth } from "../lib/auth.js";
import { DEFAULT_SETTINGS } from "../lib/defaultSettings.js";

const router: IRouter = Router();

async function runMigrationIfNeeded(): Promise<void> {
  try {
    await pool.query(`
      DO $$
      BEGIN
        IF EXISTS (
          SELECT 1 FROM information_schema.tables
          WHERE table_name = 'platform_settings'
        ) AND NOT EXISTS (
          SELECT 1 FROM information_schema.columns
          WHERE table_name = 'platform_settings' AND column_name = 'variant_name'
        ) THEN
          ALTER TABLE platform_settings ADD COLUMN variant_name TEXT NOT NULL DEFAULT 'Default';
          ALTER TABLE platform_settings DROP CONSTRAINT IF EXISTS platform_settings_pkey;
          ALTER TABLE platform_settings ADD PRIMARY KEY (platform_id, variant_name);
        END IF;
      END $$;
    `);
  } catch (_) {
    // Ignore — table may not exist yet (fresh deploy)
  }
}

async function ensureDefaultSettings(): Promise<void> {
  await runMigrationIfNeeded();
  for (const setting of DEFAULT_SETTINGS) {
    await db
      .insert(platformSettingsTable)
      .values(setting)
      .onConflictDoNothing();
  }
}

// GET /settings — all variants for all platforms
router.get("/settings", requireAuth, async (req, res): Promise<void> => {
  await ensureDefaultSettings();
  const settings = await db.select().from(platformSettingsTable);
  res.json(GetSettingsResponse.parse(settings));
});

// PUT /settings/:platformId/audience — update audience + language for all variants of a platform
router.put("/settings/:platformId/audience", requireAuth, async (req, res): Promise<void> => {
  const params = UpdatePlatformAudienceParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const body = UpdatePlatformAudienceBody.safeParse(req.body);
  if (!body.success) { res.status(400).json({ error: body.error.message }); return; }

  await db
    .update(platformSettingsTable)
    .set({ audience: body.data.audience, language: body.data.language, updatedAt: new Date() })
    .where(eq(platformSettingsTable.platformId, params.data.platformId));

  res.json({ ok: true });
});

// PUT /settings/:platformId/:variantName — update instructions for a specific variant
router.put("/settings/:platformId/:variantName", requireAuth, async (req, res): Promise<void> => {
  const params = UpdateVariantParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const body = UpdateVariantBody.safeParse(req.body);
  if (!body.success) { res.status(400).json({ error: body.error.message }); return; }

  const [updated] = await db
    .update(platformSettingsTable)
    .set({ instructions: body.data.instructions, variantName: body.data.variantName, updatedAt: new Date() })
    .where(and(
      eq(platformSettingsTable.platformId, params.data.platformId),
      eq(platformSettingsTable.variantName, params.data.variantName),
    ))
    .returning();

  if (!updated) { res.status(404).json({ error: "Variant not found" }); return; }

  res.json(UpdateVariantResponse.parse(updated));
});

// POST /settings/:platformId — add a new variant
router.post("/settings/:platformId", requireAuth, async (req, res): Promise<void> => {
  const params = CreateVariantParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const body = CreateVariantBody.safeParse(req.body);
  if (!body.success) { res.status(400).json({ error: body.error.message }); return; }

  // Inherit audience and language from existing variants of this platform
  const existing = await db
    .select()
    .from(platformSettingsTable)
    .where(eq(platformSettingsTable.platformId, params.data.platformId))
    .limit(1);

  if (!existing.length) { res.status(404).json({ error: "Platform not found" }); return; }

  const [created] = await db
    .insert(platformSettingsTable)
    .values({
      platformId: params.data.platformId,
      variantName: body.data.variantName,
      instructions: body.data.instructions,
      audience: existing[0].audience,
      language: existing[0].language,
    })
    .returning();

  res.status(201).json(UpdateVariantResponse.parse(created));
});

// DELETE /settings/:platformId/:variantName — delete a variant (must keep at least one)
router.delete("/settings/:platformId/:variantName", requireAuth, async (req, res): Promise<void> => {
  const params = DeleteVariantParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const variants = await db
    .select()
    .from(platformSettingsTable)
    .where(eq(platformSettingsTable.platformId, params.data.platformId));

  if (variants.length <= 1) {
    res.status(400).json({ error: "Cannot delete the last variant" });
    return;
  }

  await db
    .delete(platformSettingsTable)
    .where(and(
      eq(platformSettingsTable.platformId, params.data.platformId),
      eq(platformSettingsTable.variantName, params.data.variantName),
    ));

  res.status(204).send();
});

export default router;

import { useState, useEffect } from "react";
import { Layout } from "@/components/layout";
import {
  useGetSettings,
  useUpdatePlatformAudience,
  useUpdateVariant,
  useCreateVariant,
  useDeleteVariant,
} from "@workspace/api-client-react";
import { PlatformIcon, platformLabel } from "@/components/platform-icon";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { Loader2, Save, Plus, Trash2 } from "lucide-react";
import { motion } from "framer-motion";
import { useQueryClient } from "@tanstack/react-query";

const PLATFORM_ORDER = ["instagram", "facebook", "substack_post", "substack_note", "x", "bluesky"];

type VariantLocal = { variantName: string; instructions: string; isDirty: boolean };
type PlatformLocal = { audience: string; language: string; audienceDirty: boolean; variants: VariantLocal[] };

export default function Settings() {
  const { data: settings, isLoading } = useGetSettings();
  const updateAudienceMutation = useUpdatePlatformAudience();
  const updateVariantMutation = useUpdateVariant();
  const createVariantMutation = useCreateVariant();
  const deleteVariantMutation = useDeleteVariant();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [local, setLocal] = useState<Record<string, PlatformLocal>>({});
  const [saving, setSaving] = useState<string | null>(null);

  useEffect(() => {
    if (!settings) return;
    const grouped: Record<string, PlatformLocal> = {};
    for (const s of settings) {
      if (!grouped[s.platformId]) {
        grouped[s.platformId] = { audience: s.audience, language: s.language, audienceDirty: false, variants: [] };
      }
      grouped[s.platformId].variants.push({ variantName: s.variantName, instructions: s.instructions, isDirty: false });
    }
    setLocal(grouped);
  }, [settings]);

  const refresh = () => queryClient.invalidateQueries({ queryKey: ["/api/settings"] });

  const setAudience = (pid: string, value: string) =>
    setLocal(prev => ({ ...prev, [pid]: { ...prev[pid], audience: value, audienceDirty: true } }));

  const setLanguage = (pid: string, value: string) =>
    setLocal(prev => ({ ...prev, [pid]: { ...prev[pid], language: value, audienceDirty: true } }));

  const setVariantField = (pid: string, idx: number, field: "variantName" | "instructions", value: string) =>
    setLocal(prev => {
      const variants = [...prev[pid].variants];
      variants[idx] = { ...variants[idx], [field]: value, isDirty: true };
      return { ...prev, [pid]: { ...prev[pid], variants } };
    });

  const handleSaveAudience = async (pid: string) => {
    setSaving(`${pid}_audience`);
    try {
      await updateAudienceMutation.mutateAsync({ platformId: pid, data: { audience: local[pid].audience, language: local[pid].language } });
      setLocal(prev => ({ ...prev, [pid]: { ...prev[pid], audienceDirty: false } }));
      toast({ title: "Saved", description: `${platformLabel(pid)} audience updated.` });
      refresh();
    } catch {
      toast({ variant: "destructive", title: "Error", description: "Failed to save." });
    } finally {
      setSaving(null);
    }
  };

  const handleSaveVariant = async (pid: string, idx: number, originalName: string) => {
    setSaving(`${pid}_${idx}`);
    try {
      const v = local[pid].variants[idx];
      await updateVariantMutation.mutateAsync({ platformId: pid, variantName: originalName, data: { variantName: v.variantName, instructions: v.instructions } });
      const variants = [...local[pid].variants];
      variants[idx] = { ...variants[idx], isDirty: false };
      setLocal(prev => ({ ...prev, [pid]: { ...prev[pid], variants } }));
      toast({ title: "Saved", description: `"${v.variantName}" style saved.` });
      refresh();
    } catch {
      toast({ variant: "destructive", title: "Error", description: "Failed to save." });
    } finally {
      setSaving(null);
    }
  };

  const handleAddVariant = async (pid: string) => {
    setSaving(`${pid}_add`);
    try {
      const name = `Style ${(local[pid]?.variants.length ?? 0) + 1}`;
      await createVariantMutation.mutateAsync({ platformId: pid, data: { variantName: name, instructions: "" } });
      toast({ title: "Added", description: `New style variant added to ${platformLabel(pid)}.` });
      refresh();
    } catch {
      toast({ variant: "destructive", title: "Error", description: "Failed to add variant." });
    } finally {
      setSaving(null);
    }
  };

  const handleDeleteVariant = async (pid: string, variantName: string) => {
    setSaving(`${pid}_del_${variantName}`);
    try {
      await deleteVariantMutation.mutateAsync({ platformId: pid, variantName });
      toast({ title: "Deleted", description: `"${variantName}" style removed.` });
      refresh();
    } catch (e: any) {
      toast({ variant: "destructive", title: "Error", description: e?.message ?? "Failed to delete." });
    } finally {
      setSaving(null);
    }
  };

  if (isLoading) {
    return (
      <Layout>
        <div className="flex items-center justify-center h-64">
          <Loader2 className="w-8 h-8 text-primary animate-spin" />
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="mb-10">
        <h1 className="text-4xl font-serif font-bold text-foreground mb-4">Platform Configuration</h1>
        <p className="text-muted-foreground text-lg max-w-2xl">
          Set the audience and language for each platform, then define one or more writing style variants. Each variant generates a separate caption.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {PLATFORM_ORDER.map((pid, idx) => {
          const config = local[pid];
          if (!config) return null;

          return (
            <motion.div
              key={pid}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: idx * 0.07 }}
              className="glass-panel rounded-2xl p-6 md:p-8 flex flex-col gap-6"
            >
              {/* Platform header */}
              <div className="flex items-center gap-3 border-b border-white/10 pb-4">
                <PlatformIcon platform={pid} className="text-2xl" />
                <h2 className="text-xl font-serif font-bold">{platformLabel(pid)}</h2>
              </div>

              {/* Audience + Language (shared across all variants) */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <label className="text-xs font-semibold text-muted-foreground uppercase tracking-widest">
                    Target Audience
                  </label>
                  <select
                    value={config.language}
                    onChange={(e) => setLanguage(pid, e.target.value)}
                    className="bg-black/30 border border-white/10 rounded-lg px-3 py-1.5 text-sm text-foreground focus:outline-none focus:border-primary"
                  >
                    <option value="en">English</option>
                    <option value="ar">Arabic</option>
                    <option value="fr">French</option>
                    <option value="es">Spanish</option>
                    <option value="it">Italian</option>
                  </select>
                </div>
                <input
                  type="text"
                  value={config.audience}
                  onChange={(e) => setAudience(pid, e.target.value)}
                  className="w-full bg-black/20 border border-white/5 rounded-xl px-4 py-3 text-sm text-foreground focus:outline-none focus:border-primary/50 font-sans"
                  placeholder="E.g., Policy makers, general public..."
                />
                {config.audienceDirty && (
                  <Button
                    size="sm"
                    variant="outline"
                    className="gap-2 border-white/10 hover:bg-white/5 text-xs"
                    disabled={saving === `${pid}_audience`}
                    onClick={() => handleSaveAudience(pid)}
                  >
                    {saving === `${pid}_audience` ? <Loader2 className="w-3 h-3 animate-spin" /> : <Save className="w-3 h-3" />}
                    Save Audience
                  </Button>
                )}
              </div>

              {/* Style Variants */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <label className="text-xs font-semibold text-muted-foreground uppercase tracking-widest">
                    Writing Styles
                  </label>
                  <Button
