                        <Button
                          size="sm"
                          className="gap-2 w-full text-xs"
                          disabled={isSaving}
                          onClick={() => handleSaveVariant(pid, i, originalName)}
                        >
                          {isSaving ? <Loader2 className="w-3 h-3 animate-spin" /> : <Save className="w-3 h-3" />}
                          Save "{v.variantName}"
                        </Button>
                      )}
                    </div>
                  );
                })}
              </div>
            </motion.div>
          );
        })}
      </div>
    </Layout>
  );
}

