      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {PLATFORM_ORDER.map((pid, idx) => {
          const config = local[pid];
          if (!config) return null;

          return (
            <motion.div
              key={pid}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: idx * 0.07 }}
              className="glass-panel rounded-2xl p-6 md:p-8 flex flex-col gap-6"
            >
              {/* Platform header */}
              <div className="flex items-center gap-3 border-b border-white/10 pb-4">
                <PlatformIcon platform={pid} className="text-2xl" />
                <h2 className="text-xl font-serif font-bold">{platformLabel(pid)}</h2>
              </div>

              {/* Audience + Language (shared across all variants) */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <label className="text-xs font-semibold text-muted-foreground uppercase tracking-widest">
                    Target Audience
                  </label>
                  <select
                    value={config.language}
                    onChange={(e) => setLanguage(pid, e.target.value)}
                    className="bg-black/30 border border-white/10 rounded-lg px-3 py-1.5 text-sm text-foreground focus:outline-none focus:border-primary"
                  >
                    <option value="en">English</option>
                    <option value="ar">Arabic</option>
                    <option value="fr">French</option>
                    <option value="es">Spanish</option>
                    <option value="it">Italian</option>
                  </select>
                </div>
                <input
                  type="text"
                  value={config.audience}
                  onChange={(e) => setAudience(pid, e.target.value)}
                  className="w-full bg-black/20 border border-white/5 rounded-xl px-4 py-3 text-sm text-foreground focus:outline-none focus:border-primary/50 font-sans"
                  placeholder="E.g., Policy makers, general public..."
                />
                {config.audienceDirty && (
                  <Button
                    size="sm"
                    variant="outline"
                    className="gap-2 border-white/10 hover:bg-white/5 text-xs"
                    disabled={saving === `${pid}_audience`}
                    onClick={() => handleSaveAudience(pid)}
                  >
                    {saving === `${pid}_audience` ? <Loader2 className="w-3 h-3 animate-spin" /> : <Save className="w-3 h-3" />}
                    Save Audience
                  </Button>
                )}
              </div>

              {/* Style Variants */}
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <label className="text-xs font-semibold text-muted-foreground uppercase tracking-widest">
                    Writing Styles
                  </label>
                  <Button
                    size="sm"
                    variant="ghost"
                    className="gap-1.5 text-xs text-primary hover:text-primary/80 hover:bg-transparent px-0"
                    disabled={saving === `${pid}_add`}
                    onClick={() => handleAddVariant(pid)}
                  >
                    {saving === `${pid}_add` ? <Loader2 className="w-3 h-3 animate-spin" /> : <Plus className="w-3 h-3" />}
                    Add style
                  </Button>
                </div>

                {config.variants.map((v, i) => {
                  const isSaving = saving === `${pid}_${i}`;
                  const isDeleting = saving === `${pid}_del_${v.originalName}`;

                  return (
                    <div key={i} className="bg-white/[0.03] border border-white/5 rounded-xl p-4 space-y-3">
                      <div className="flex items-center gap-2">
                        <input
                          value={v.variantName}
                          onChange={(e) => setVariantField(pid, i, "variantName", e.target.value)}
                          className="flex-1 bg-black/30 border border-white/10 rounded-lg px-3 py-1.5 text-sm font-semibold text-foreground focus:outline-none focus:border-primary/50"
                          placeholder="Style name (e.g. Formal, Punchy...)"
                        />
                        {config.variants.length > 1 && (
                          <Button
                            size="icon"
                            variant="ghost"
                            className="w-8 h-8 text-muted-foreground hover:text-destructive"
                            disabled={isDeleting}
                            onClick={() => handleDeleteVariant(pid, v.originalName)}
                          >
                            {isDeleting ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Trash2 className="w-3.5 h-3.5" />}
                          </Button>
                        )}
                      </div>
                      <textarea
                        value={v.instructions}
                        onChange={(e) => setVariantField(pid, i, "instructions", e.target.value)}
                        rows={3}
                        className="w-full bg-black/20 border border-white/5 rounded-lg px-3 py-2 text-sm text-foreground focus:outline-none focus:border-primary/50 resize-none font-sans"
                        placeholder="Writing instructions for this style..."
                      />
                      {v.isDirty && (
                        <Button
                          size="sm"
                          className="gap-2 w-full text-xs"
                          disabled={isSaving}
                          onClick={() => handleSaveVariant(pid, i)}
                        >
                          {isSaving ? <Loader2 className="w-3 h-3 animate-spin" /> : <Save className="w-3 h-3" />}
                          Save "{v.variantName}"
                        </Button>
                      )}
                    </div>
                  );
                })}
              </div>
            </motion.div>
          );
        })}
      </div>
    </Layout>
  );
}

