import { Router, type IRouter } from "express";
import { and, eq } from "drizzle-orm";
import { db, pool, platformSettingsTable } from "@workspace/db";
import {
  GetSettingsResponse,
  UpdateVariantBody,
  UpdateVariantParams,
  UpdateVariantResponse,
  CreateVariantBody,
  CreateVariantParams,
  DeleteVariantParams,
  UpdatePlatformAudienceBody,
  UpdatePlatformAudienceParams,
} from "@workspace/api-zod";
import { requireAuth } from "../lib/auth.js";
import { DEFAULT_SETTINGS } from "../lib/defaultSettings.js";

const router: IRouter = Router();

async function runMigrationIfNeeded(): Promise<void> {
  // Create table with correct schema if it doesn't exist yet (fresh deploy)
  await pool.query(`
    CREATE TABLE IF NOT EXISTS platform_settings (
      platform_id TEXT NOT NULL,
      variant_name TEXT NOT NULL DEFAULT 'Default',
      instructions TEXT NOT NULL,
      audience TEXT NOT NULL,
      language TEXT NOT NULL DEFAULT 'en',
      updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
      PRIMARY KEY (platform_id, variant_name)
    );
  `);

  // Upgrade old schema (single PK on platform_id, no variant_name column)
  await pool.query(`
    DO $$
    DECLARE
      pk_name TEXT;
    BEGIN
      IF NOT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_name = 'platform_settings' AND column_name = 'variant_name'
      ) THEN
        ALTER TABLE platform_settings ADD COLUMN variant_name TEXT NOT NULL DEFAULT 'Default';

        SELECT constraint_name INTO pk_name
        FROM information_schema.table_constraints
        WHERE table_name = 'platform_settings' AND constraint_type = 'PRIMARY KEY';

        IF pk_name IS NOT NULL THEN
          EXECUTE 'ALTER TABLE platform_settings DROP CONSTRAINT ' || quote_ident(pk_name);
        END IF;

        ALTER TABLE platform_settings ADD PRIMARY KEY (platform_id, variant_name);
      END IF;
    END $$;
  `);
}

async function ensureDefaultSettings(): Promise<void> {
  await runMigrationIfNeeded();
  for (const setting of DEFAULT_SETTINGS) {
    await db
      .insert(platformSettingsTable)
      .values(setting)
      .onConflictDoNothing();
  }
}

// GET /settings — all variants for all platforms
router.get("/settings", requireAuth, async (req, res): Promise<void> => {
  await ensureDefaultSettings();
  const settings = await db.select().from(platformSettingsTable);
  res.json(GetSettingsResponse.parse(settings));
});

// PUT /settings/:platformId/audience — update audience + language for all variants of a platform
router.put("/settings/:platformId/audience", requireAuth, async (req, res): Promise<void> => {
  const params = UpdatePlatformAudienceParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const body = UpdatePlatformAudienceBody.safeParse(req.body);
  if (!body.success) { res.status(400).json({ error: body.error.message }); return; }

  await db
    .update(platformSettingsTable)
    .set({ audience: body.data.audience, language: body.data.language, updatedAt: new Date() })
    .where(eq(platformSettingsTable.platformId, params.data.platformId));

  res.json({ ok: true });
});

// PUT /settings/:platformId/:variantName — update instructions for a specific variant
router.put("/settings/:platformId/:variantName", requireAuth, async (req, res): Promise<void> => {
  const params = UpdateVariantParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const body = UpdateVariantBody.safeParse(req.body);
  if (!body.success) { res.status(400).json({ error: body.error.message }); return; }

  const [updated] = await db
    .update(platformSettingsTable)
    .set({ instructions: body.data.instructions, variantName: body.data.variantName, updatedAt: new Date() })
    .where(and(
      eq(platformSettingsTable.platformId, params.data.platformId),
      eq(platformSettingsTable.variantName, params.data.variantName),
    ))
    .returning();

  if (!updated) { res.status(404).json({ error: "Variant not found" }); return; }

  res.json(UpdateVariantResponse.parse(updated));
});

// POST /settings/:platformId — add a new variant
router.post("/settings/:platformId", requireAuth, async (req, res): Promise<void> => {
  const params = CreateVariantParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const body = CreateVariantBody.safeParse(req.body);
  if (!body.success) { res.status(400).json({ error: body.error.message }); return; }

  // Inherit audience and language from existing variants of this platform
  const existing = await db
    .select()
    .from(platformSettingsTable)
    .where(eq(platformSettingsTable.platformId, params.data.platformId))
    .limit(1);

  if (!existing.length) { res.status(404).json({ error: "Platform not found" }); return; }

  const [created] = await db
    .insert(platformSettingsTable)
    .values({
      platformId: params.data.platformId,
      variantName: body.data.variantName,
      instructions: body.data.instructions,
      audience: existing[0].audience,
      language: existing[0].language,
    })
    .returning();

  res.status(201).json(UpdateVariantResponse.parse(created));
});

// DELETE /settings/:platformId/:variantName — delete a variant (must keep at least one)
router.delete("/settings/:platformId/:variantName", requireAuth, async (req, res): Promise<void> => {
  const params = DeleteVariantParams.safeParse(req.params);
  if (!params.success) { res.status(400).json({ error: params.error.message }); return; }

  const variants = await db
    .select()
    .from(platformSettingsTable)
    .where(eq(platformSettingsTable.platformId, params.data.platformId));

  if (variants.length <= 1) {
    res.status(400).json({ error: "Cannot delete the last variant" });
    return;
  }

  await db
    .delete(platformSettingsTable)
    .where(and(
      eq(platformSettingsTable.platformId, params.data.platformId),
      eq(platformSettingsTable.variantName, params.data.variantName),
    ));

  res.status(204).send();
});

export default router;

